function addToCart(productName, price) {
    // Create toast container if it doesn't exist
    let toastContainer = document.querySelector('.toast-container');
    if (!toastContainer) {
        toastContainer = document.createElement('div');
        toastContainer.className = 'toast-container';
        toastContainer.style.cssText = `
            position: fixed;
            top: 20px;
            right: 20px;
            z-index: 99999;
            display: flex;
            flex-direction: column;
            gap: 10px;
            max-width: 400px;
            width: 100%;
            pointer-events: none;
        `;
        document.body.appendChild(toastContainer);
    }

    // Create individual toast
    const toast = document.createElement('div');
    toast.style.cssText = `
        background: #1a1a1a;
        color: #ffffff;
        padding: 16px 20px;
        border-radius: 12px;
        font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
        box-shadow: 0 8px 32px rgba(0,0,0,0.25);
        border: 1px solid rgba(255,255,255,0.08);
        display: flex;
        align-items: center;
        gap: 14px;
        transform: translateX(120%);
        animation: slideInToast 0.4s cubic-bezier(0.22, 1, 0.36, 1) forwards;
        pointer-events: auto;
        backdrop-filter: blur(10px);
        background: rgba(26, 26, 26, 0.95);
    `;
    
    toast.innerHTML = `
        <div style="
            background: #2ecc71;
            width: 36px;
            height: 36px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            flex-shrink: 0;
        ">
            <i class="ri-check-line" style="color: white; font-size: 20px;"></i>
        </div>
        <div style="flex: 1;">
            <div style="
                font-weight: 600;
                font-size: 15px;
                color: #ffffff;
                letter-spacing: 0.3px;
            ">
                ${productName}
            </div>
            <div style="
                font-size: 13px;
                color: rgba(255,255,255,0.65);
                margin-top: 2px;
                display: flex;
                align-items: center;
                gap: 6px;
            ">
                <span>Added to cart</span>
                <span style="
                    background: rgba(255,255,255,0.1);
                    padding: 0 8px;
                    border-radius: 4px;
                    font-weight: 600;
                    color: #f1c40f;
                ">${price}</span>
            </div>
        </div>
        <button onclick="this.parentElement.remove()" style="
            background: none;
            border: none;
            color: rgba(255,255,255,0.4);
            cursor: pointer;
            font-size: 18px;
            padding: 4px;
            transition: color 0.2s;
            flex-shrink: 0;
        " onmouseover="this.style.color='rgba(255,255,255,0.8)'" onmouseout="this.style.color='rgba(255,255,255,0.4)'">
            <i class="ri-close-line"></i>
        </button>
    `;

    toastContainer.appendChild(toast);

    // Add animation keyframes if not exists
    if (!document.getElementById('toastStyles')) {
        const style = document.createElement('style');
        style.id = 'toastStyles';
        style.textContent = `
            @keyframes slideInToast {
                0% {
                    transform: translateX(120%) scale(0.9);
                    opacity: 0;
                }
                100% {
                    transform: translateX(0) scale(1);
                    opacity: 1;
                }
            }
            @keyframes slideOutToast {
                0% {
                    transform: translateX(0) scale(1);
                    opacity: 1;
                }
                100% {
                    transform: translateX(120%) scale(0.9);
                    opacity: 0;
                }
            }
        `;
        document.head.appendChild(style);
    }

    // Auto remove after 3.5 seconds with animation
    setTimeout(() => {
        toast.style.animation = 'slideOutToast 0.3s cubic-bezier(0.22, 1, 0.36, 1) forwards';
        setTimeout(() => {
            if (toast.parentElement) {
                toast.remove();
            }
        }, 300);
    }, 3500);

    // Hover pause - stop auto removal when hovering
    toast.addEventListener('mouseenter', () => {
        // Clear timeout if hovering
        // We'll just let it stay, user can close manually
    });

    // Update cart count (optional - if you have a cart counter)
    updateCartCount();
}

// Optional: Cart counter function
function updateCartCount() {
    let cartCount = document.querySelector('.cart-count');
    if (!cartCount) {
        // Create cart count badge if you want
        // Or just ignore if you don't have one
        return;
    }
    // Increment count
    let currentCount = parseInt(cartCount.textContent) || 0;
    cartCount.textContent = currentCount + 1;
}
    document.addEventListener("DOMContentLoaded", function() {
        new Swiper(".bookSwiper", {
            slidesPerView: 1,
            spaceBetween: 24,
            loop: true,
            autoplay: {
                delay: 4200,
                disableOnInteraction: false
            },
            pagination: {
                el: ".swiper-pagination",
                clickable: true
            },
            navigation: {
                nextEl: ".swiper-button-next",
                prevEl: ".swiper-button-prev"
            },
            breakpoints: {
                576: { slidesPerView: 2 },
                992: { slidesPerView: 3 },
                1200: { slidesPerView: 4 }
            }
        });
    });